import { useState, useEffect } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { ArrowRight, Code2, GitBranch, Sparkles, CheckCircle } from "lucide-react";

interface Repository {
  id: string;
  name: string;
  lastIndexed?: string;
  fileCount?: number;
  annotationCount?: number;
  status?: "indexed" | "indexing" | "pending";
}

export default function Home() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted) return;
    fetchRepos();
  }, [mounted]);

  const fetchRepos = async () => {
    try {
      setLoading(true);
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || "http://127.0.0.1:8000";
      const response = await fetch(`${apiUrl}/repo/`);

      if (response.ok) {
        const data = await response.json();
        setRepos(Array.isArray(data) ? data : []);
      } else if (response.status === 404) {
        setRepos([]);
      } else {
        setRepos([]);
      }
    } catch (err) {
      console.error("Error fetching repos:", err);
      setRepos([]);
    } finally {
      setLoading(false);
    }
  }

  if (!mounted) return null;

  const statusBadgeColor = {
    indexed: "bg-emerald-500/10 text-emerald-700 dark:text-emerald-400",
    indexing: "bg-amber-500/10 text-amber-700 dark:text-amber-400",
    pending: "bg-slate-500/10 text-slate-700 dark:text-slate-400"
  };

  const getStatusBadge = (status?: string) => {
    const baseClass = "inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium";
    if (status === "indexed") {
      return <span className={`${baseClass} ${statusBadgeColor.indexed}`}><CheckCircle className="w-3 h-3" /> Indexed</span>;
    }
    if (status === "indexing") {
      return <span className={`${baseClass} ${statusBadgeColor.indexing}`}><div className="w-2 h-2 rounded-full bg-amber-500 animate-pulse" /> Indexing</span>;
    }
    return <span className={`${baseClass} ${statusBadgeColor.pending}`}>Pending</span>;
