"use client";

import { useState, useEffect } from "react";
import Link from "next/link";
import { Button } from "@/components/ui/button";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { ArrowRight, Code2, GitBranch, Sparkles, CheckCircle } from "lucide-react";

interface Repository {
  id: string;
  name: string;
  lastIndexed?: string;
  fileCount?: number;
  annotationCount?: number;
  status?: "indexed" | "indexing" | "pending";
}

export default function Home() {
  const [repos, setRepos] = useState<Repository[]>([]);
  const [loading, setLoading] = useState(true);
  const [mounted, setMounted] = useState(false);

  useEffect(() => {
    setMounted(true);
  }, []);

  useEffect(() => {
    if (!mounted) return;
    fetchRepos();
  }, [mounted]);

  const fetchRepos = async () => {
    try {
      setLoading(true);
      const apiUrl = process.env.NEXT_PUBLIC_API_URL || "http://127.0.0.1:8000";
      const response = await fetch(`${apiUrl}/repo/`);

      if (response.ok) {
        const data = await response.json();
        setRepos(Array.isArray(data) ? data : []);
      } else if (response.status === 404) {
        setRepos([]);
      } else {
        setRepos([]);
      }
    } catch (err) {
      console.error("Error fetching repos:", err);
      setRepos([]);
    } finally {
      setLoading(false);
    }
  }

  if (!mounted) return null;

  const statusBadgeColor = {
    indexed: "bg-emerald-500/10 text-emerald-700 dark:text-emerald-400",
    indexing: "bg-amber-500/10 text-amber-700 dark:text-amber-400",
    pending: "bg-slate-500/10 text-slate-700 dark:text-slate-400"
