  const getStatusBadge = (status?: string) => {
    const baseClass = "inline-flex items-center gap-1 px-2.5 py-1 rounded-md text-xs font-medium";
    if (status === "indexed") {
      return <span className={`${baseClass} ${statusBadgeColor.indexed}`}><CheckCircle className="w-3 h-3" /> Indexed</span>;
    }
    if (status === "indexing") {
      return <span className={`${baseClass} ${statusBadgeColor.indexing}`}><div className="w-2 h-2 rounded-full bg-amber-500 animate-pulse" /> Indexing</span>;
    }
    return <span className={`${baseClass} ${statusBadgeColor.pending}`}>Pending</span>;
  };

  return (
    <div className="min-h-screen bg-background text-foreground">
      {/* Header */}
      <header className="sticky top-0 z-50 border-b border-border/40 bg-background/80 backdrop-blur-sm">
        <div className="max-w-7xl mx-auto px-6 py-4 flex items-center justify-between">
          <div className="flex items-center gap-3">
            <div className="flex h-10 w-10 items-center justify-center rounded-lg bg-primary shadow-md">
              <span className="text-lg font-bold text-primary-foreground">DB</span>
            </div>
            <div>
