                  <CheckCircle className="w-4 h-4" />
                  {repos.length} {repos.length === 1 ? "repository" : "repositories"} ready
                </div>
              )}

              <Link href={repos.length > 0 ? `/repo/${repos[0].id}` : "#repos"}>
